export function getPrefecture(code: number, subRegion?: string): PrefectureShape | undefined {
  if (subRegion) {
    const key = `${code}-${subRegion}`;
    return subRegionPrefectures[key] || prefectures[code];
  }
  return prefectures[code];
}
